<?php/** * Template Functions * * @package AquaLuxe * @subpackage Helpers * @since 1.0.0 *//** * Sanitize checkbox * * @param boolean $input Checkbox value. * @return boolean */function aqualuxe_sanitize_checkbox( $input ) {    return ( isset( $input ) && true === $input ) ? true : false;}/** * Sanitize select * * @param string $input Select value. * @param object $setting Setting object. * @return string */function aqualuxe_sanitize_select( $input, $setting ) {    // Get the list of possible select options    $choices = $setting->manager->get_control( $setting->id )->choices;        // Return input if valid or return default option    return ( array_key_exists( $input, $choices ) ? $input : $setting->default );}/** * Sanitize float * * @param float $input Float value. * @return float */function aqualuxe_sanitize_float( $input ) {    return filter_var( $input, FILTER_SANITIZE_NUMBER_FLOAT, FILTER_FLAG_ALLOW_FRACTION );}/** * Get header layout * * @return string */function aqualuxe_get_header_layout() {    return get_theme_mod( 'aqualuxe_header_layout', 'default' );}/** * Get footer layout * * @return string */function aqualuxe_get_footer_layout() {    return get_theme_mod( 'aqualuxe_footer_layout', 'default' );}/** * Get sidebar position * * @return string */function aqualuxe_get_sidebar_position() {    // Check if WooCommerce is active and we're on a WooCommerce page    if ( class_exists( 'WooCommerce' ) && ( is_woocommerce() || is_cart() || is_checkout() || is_account_page() ) ) {        return get_theme_mod( 'aqualuxe_shop_sidebar_position', 'left' );    }        // Check if we're on a single page or post    if ( is_page() || is_single() ) {        // Get page/post specific sidebar position        $sidebar_position = get_post_meta( get_the_ID(), '_aqualuxe_sidebar_position', true );                // If page/post specific sidebar position is set, use it        if ( ! empty( $sidebar_position ) ) {            return $sidebar_position;        }    }        // Use default sidebar position    return get_theme_mod( 'aqualuxe_sidebar_position', 'right' );}/** * Check if sidebar should be displayed * * @return boolean */function aqualuxe_has_sidebar() {    // Get sidebar position    $sidebar_position = aqualuxe_get_sidebar_position();        // Check if sidebar is disabled    if ( 'none' === $sidebar_position ) {        return false;    }        // Check if we're on a WooCommerce page    if ( class_exists( 'WooCommerce' ) && is_woocommerce() ) {        // Check if shop sidebar is active        return is_active_sidebar( 'shop-sidebar' );    }        // Check if we're on a product page    if ( class_exists( 'WooCommerce' ) && is_product() ) {        // Check if product sidebar is active        return is_active_sidebar( 'product-sidebar' );    }        // Check if we're on the homepage    if ( is_front_page() && ! is_home() ) {        // Check if home sidebar is active        return is_active_sidebar( 'home-sidebar' );    }        // Check if main sidebar is active    return is_active_sidebar( 'sidebar-1' );}/** * Get container class * * @return string */function aqualuxe_get_container_class() {    // Get page layout    $page_layout = get_theme_mod( 'aqualuxe_page_layout', 'default' );        // Check if we're on a single page or post    if ( is_page() || is_single() ) {        // Get page/post specific layout        $specific_layout = get_post_meta( get_the_ID(), '_aqualuxe_page_layout', true );                // If page/post specific layout is set, use it        if ( ! empty( $specific_layout ) ) {            $page_layout = $specific_layout;        }    }        // Return container class based on page layout    switch ( $page_layout ) {        case 'full-width':            return 'container-fluid';        case 'boxed':            return 'container-boxed';        case 'contained':            return 'container-contained';        default:            return 'container';    }}/** * Get blog layout * * @return string */function aqualuxe_get_blog_layout() {    return get_theme_mod( 'aqualuxe_blog_layout', 'standard' );}/** * Get shop layout * * @return string */function aqualuxe_get_shop_layout() {    // Check if WooCommerce is active    if ( ! class_exists( 'WooCommerce' ) ) {        return 'grid';    }        // Check if we have a cookie set for the view    if ( isset( $_COOKIE['aqualuxe_shop_view'] ) ) {        return sanitize_text_field( $_COOKIE['aqualuxe_shop_view'] );    }        // Use default shop layout    return get_theme_mod( 'aqualuxe_shop_layout', 'grid' );}/** * Get excerpt length * * @return int */function aqualuxe_get_excerpt_length() {    return get_theme_mod( 'aqualuxe_blog_excerpt_length', 55 );}/** * Custom excerpt length * * @param int $length Excerpt length. * @return int */function aqualuxe_excerpt_length( $length ) {    return aqualuxe_get_excerpt_length();}add_filter( 'excerpt_length', 'aqualuxe_excerpt_length' );/** * Custom excerpt more * * @param string $more More string. * @return string */function aqualuxe_excerpt_more( $more ) {    return '...';}add_filter( 'excerpt_more', 'aqualuxe_excerpt_more' );/** * Get read more text * * @return string */function aqualuxe_get_read_more_text() {    return get_theme_mod( 'aqualuxe_blog_read_more_text', esc_html__( 'Read More', 'aqualuxe' ) );}/** * Get social links * * @return array */function aqualuxe_get_social_links() {    $social_links = [];        // Facebook    $facebook = get_theme_mod( 'aqualuxe_facebook', '' );    if ( ! empty( $facebook ) ) {        $social_links['facebook'] = [            'url'   => $facebook,            'label' => esc_html__( 'Facebook', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 2h-3a5 5 0 0 0-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 0 1 1-1h3z"></path></svg>',        ];    }        // Twitter    $twitter = get_theme_mod( 'aqualuxe_twitter', '' );    if ( ! empty( $twitter ) ) {        $social_links['twitter'] = [            'url'   => $twitter,            'label' => esc_html__( 'Twitter', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M23 3a10.9 10.9 0 0 1-3.14 1.53 4.48 4.48 0 0 0-7.86 3v1A10.66 10.66 0 0 1 3 4s-4 9 5 13a11.64 11.64 0 0 1-7 2c9 5 20 0 20-11.5a4.5 4.5 0 0 0-.08-.83A7.72 7.72 0 0 0 23 3z"></path></svg>',        ];    }        // Instagram    $instagram = get_theme_mod( 'aqualuxe_instagram', '' );    if ( ! empty( $instagram ) ) {        $social_links['instagram'] = [            'url'   => $instagram,            'label' => esc_html__( 'Instagram', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="2" width="20" height="20" rx="5" ry="5"></rect><path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path><line x1="17.5" y1="6.5" x2="17.51" y2="6.5"></line></svg>',        ];    }        // LinkedIn    $linkedin = get_theme_mod( 'aqualuxe_linkedin', '' );    if ( ! empty( $linkedin ) ) {        $social_links['linkedin'] = [            'url'   => $linkedin,            'label' => esc_html__( 'LinkedIn', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-2-2 2 2 0 0 0-2 2v7h-4v-7a6 6 0 0 1 6-6z"></path><rect x="2" y="9" width="4" height="12"></rect><circle cx="4" cy="4" r="2"></circle></svg>',        ];    }        // YouTube    $youtube = get_theme_mod( 'aqualuxe_youtube', '' );    if ( ! empty( $youtube ) ) {        $social_links['youtube'] = [            'url'   => $youtube,            'label' => esc_html__( 'YouTube', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22.54 6.42a2.78 2.78 0 0 0-1.94-2C18.88 4 12 4 12 4s-6.88 0-8.6.46a2.78 2.78 0 0 0-1.94 2A29 29 0 0 0 1 11.75a29 29 0 0 0 .46 5.33A2.78 2.78 0 0 0 3.4 19c1.72.46 8.6.46 8.6.46s6.88 0 8.6-.46a2.78 2.78 0 0 0 1.94-2 29 29 0 0 0 .46-5.25 29 29 0 0 0-.46-5.33z"></path><polygon points="9.75 15.02 15.5 11.75 9.75 8.48 9.75 15.02"></polygon></svg>',        ];    }        // Pinterest    $pinterest = get_theme_mod( 'aqualuxe_pinterest', '' );    if ( ! empty( $pinterest ) ) {        $social_links['pinterest'] = [            'url'   => $pinterest,            'label' => esc_html__( 'Pinterest', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M8 12a4 4 0 1 0 8 0 4 4 0 0 0-8 0z"></path><path d="M12 2v2"></path><path d="M12 20v2"></path><path d="M4.93 4.93l1.41 1.41"></path><path d="M17.66 17.66l1.41 1.41"></path><path d="M2 12h2"></path><path d="M20 12h2"></path><path d="M6.34 17.66l-1.41 1.41"></path><path d="M19.07 4.93l-1.41 1.41"></path></svg>',        ];    }        // TikTok    $tiktok = get_theme_mod( 'aqualuxe_tiktok', '' );    if ( ! empty( $tiktok ) ) {        $social_links['tiktok'] = [            'url'   => $tiktok,            'label' => esc_html__( 'TikTok', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 12a4 4 0 1 0 0 8 4 4 0 0 0 0-8z"></path><path d="M16 8v5a3 3 0 0 1-6 0v-1"></path><path d="M12 4v4"></path><path d="M15 4v4"></path><path d="M15 8h-3"></path></svg>',        ];    }        // WhatsApp    $whatsapp = get_theme_mod( 'aqualuxe_whatsapp', '' );    if ( ! empty( $whatsapp ) ) {        $social_links['whatsapp'] = [            'url'   => $whatsapp,            'label' => esc_html__( 'WhatsApp', 'aqualuxe' ),            'icon'  => '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"></path></svg>',        ];    }        return $social_links;}